{
  "name": "BidPilot MVP",
  "description": "An autonomous agentic AI ecosystem for proposal management and RFP automation using Gemini 3.0."
}

export interface LogEntry {
  id: number;
  agent: 'Historian' | 'Gatekeeper' | 'Architect' | 'Quant' | 'Auditor' | 'System';
  message: string;
  timestamp: string;
  type: 'info' | 'success' | 'error' | 'warning' | 'thinking';
}

export interface Constraint {
  id: string;
  label: string;
  value: string;
  type: 'text' | 'number';
}

export interface Document {
  id: number;
  name: string;
  size: string;
  date: string;
  tags: string[];
  type: 'pdf' | 'docx' | 'xlsx';
  status: 'indexed' | 'pending' | 'error';
}

export interface SimulationState {
  isActive: boolean;
  currentAgent: string | null;
  progress: number;
  verdict: 'pending' | 'go' | 'no-go';
}

import { GoogleGenAI, Type } from "@google/genai";

// Initialize the Gemini Client
// In a real app, we would handle missing keys more gracefully in the UI.
const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

/**
 * The Historian Agent: Summarizes and indexes documents.
 * Uses a faster model for bulk processing.
 */
export const runHistorianAgent = async (docName: string): Promise<string> => {
  if (!apiKey) return `[Simulated] Indexed content from ${docName} into Knowledge Graph.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are "The Historian", an AI agent responsible for indexing corporate knowledge. 
      Analyze this filename and generate a brief, professional summary of what kind of data it likely contains for a proposal library.
      Filename: ${docName}`,
    });
    return response.text || `Indexed ${docName}`;
  } catch (error) {
    console.error("Historian Error:", error);
    return `[Fallback] Indexed content from ${docName}.`;
  }
};

/**
 * The Gatekeeper Agent: Decides Go/No-Go based on risk.
 * Uses High-Reasoning model with Thinking Budget.
 */
export const runGatekeeperAgent = async (rfpText: string, constraints: string): Promise<{verdict: string, reasoning: string}> => {
  if (!apiKey) return { 
    verdict: "GO", 
    reasoning: "[Simulated] Logic checks passed. Budget within range. Stack compatible." 
  };

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `You are "The Gatekeeper", a strict risk analysis AI for RFP proposals.

      Your constraints are: ${constraints}

      The RFP content is:
      ---
      ${rfpText}
      ---

      Determine a "GO" or "NO-GO" verdict. Explain your reasoning in bullet points.
      If the budget is too low or forbidden tech is required, say NO-GO. Otherwise GO.`,
      config: {
        thinkingConfig: { thinkingBudget: 1024 }, // Allocating thinking tokens for reasoning
      }
    });

    const text = response.text || "";
    const verdict = text.toUpperCase().includes("NO-GO") ? "NO-GO" : "GO";
    return { verdict, reasoning: text };
  } catch (error) {
    console.error("Gatekeeper Error:", error);
    return { verdict: "GO", reasoning: "Analysis failed, defaulting to manual review." };
  }
};

/**
 * The Architect Agent: Drafts the proposal.
 * Uses Search Grounding to find latest market info if needed.
 */
export const runArchitectAgent = async (rfpText: string): Promise<string> => {
  if (!apiKey) return `[Simulated Draft]\n\nExecutive Summary:\nBidPilot proposes a comprehensive cloud migration strategy...`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `You are "The Architect", a senior proposal writer. Write a compelling Executive Summary for this RFP.
      Use a persuasive, professional tone. Highlight our strengths in Cloud Migration and ISO 27001 compliance.

      RFP Context: ${rfpText}`,
      config: {
        tools: [{ googleSearch: {} }], // Use search to ground valid tech terms if needed
        responseMimeType: 'text/plain'
      }
    });
    return response.text || "Draft generation failed.";
  } catch (error) {
    console.error("Architect Error:", error);
    return "Error generating draft. Please check API Key.";
  }
};

/**
 * The Quant Agent: Analyzes specific data structures (Excel/JSON).
 * Uses fast model for structured data manipulation.
 */
export const runQuantAgent = async (question: string): Promise<string> => {
  if (!apiKey) return `def solve_security_compliance():\n    return True # Compliance Verified`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are "The Quant", a technical agent that writes Python code to solve data problems.
      Write a short Python function that validates this security requirement: "${question}"
      Return ONLY the python code block.`,
    });
    return response.text || "# Error generating code";
  } catch (error) {
    console.error("Quant Error:", error);
    return "# API Error";
  }
};

import React, { useState, useEffect, useRef } from 'react';
import {
  ShieldAlert,
  FileText,
  CheckCircle,
  XCircle,
  Settings,
  Terminal,
  Activity,
  ChevronRight,
  BrainCircuit,
  FileSpreadsheet,
  AlertTriangle,
  Play,
  LayoutDashboard,
  Database,
  PenTool,
  Code,
  Search,
  Cpu
} from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { LogEntry, SimulationState } from './types';
import { INITIAL_CONSTRAINTS, MOCK_KNOWLEDGE_BASE, MOCK_RFP_CONTENT } from './constants';
import * as GeminiService from './services/geminiService';

// --- Reusable Components ---

const Badge = ({ children, variant = "default" }: { children: React.ReactNode, variant?: string }) => {
  const styles: Record<string, string> = {
    default: "bg-slate-100 text-slate-700",
    success: "bg-emerald-100 text-emerald-700",
    error: "bg-rose-100 text-rose-700",
    warning: "bg-amber-100 text-amber-700",
    thinking: "bg-purple-100 text-purple-700 animate-pulse",
    code: "bg-slate-800 text-slate-200 font-mono",
  };
  return (
    <span className={`px-2.5 py-0.5 rounded-full text-xs font-medium ${styles[variant] || styles.default}`}>
      {children}
    </span>
  );
};

// --- Main App ---

export default function BidPilotApp() {
  const [view, setView] = useState<'dashboard' | 'analysis' | 'knowledge' | 'draft'>('dashboard');
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [simState, setSimState] = useState<SimulationState>({
    isActive: false,
    currentAgent: null,
    progress: 0,
    verdict: 'pending'
  });
  const [draftContent, setDraftContent] = useState("");
  const [gatekeeperReasoning, setGatekeeperReasoning] = useState("");
  const logsEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll logs
  useEffect(() => {
    if (view === 'analysis') {
      logsEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }, [logs, view]);

  const addLog = (agent: LogEntry['agent'], message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [...prev, {
      id: Date.now(),
      agent,
      message,
      timestamp: new Date().toLocaleTimeString().split(' ')[0],
      type
    }]);
  };

  const runSimulation = async () => {
    if (simState.isActive) return;

    setView('analysis');
    setSimState({ isActive: true, currentAgent: 'Historian', progress: 0, verdict: 'pending' });
    setLogs([]);
    setDraftContent("");
    setGatekeeperReasoning("");

    // 1. Historian: Ingest
    addLog('System', 'Initializing Agent Swarm...', 'info');
    await new Promise(r => setTimeout(r, 800));

    addLog('Historian', 'Scanning Knowledge Base...', 'thinking');
    setSimState(prev => ({ ...prev, currentAgent: 'Historian', progress: 10 }));

    // Call Gemini for Historian
    const histMsg = await GeminiService.runHistorianAgent(MOCK_KNOWLEDGE_BASE[0].name);
    addLog('Historian', histMsg, 'success');
    addLog('Historian', 'Cross-referencing 4 documents with RFP context.', 'info');
    await new Promise(r => setTimeout(r, 1000));

    // 2. Gatekeeper: Analysis
    addLog('Gatekeeper', 'Analyzing RFP against "Kill Switch" constraints...', 'thinking');
    setSimState(prev => ({ ...prev, currentAgent: 'Gatekeeper', progress: 30 }));

    const constraintsText = INITIAL_CONSTRAINTS.map(c => `${c.label}: ${c.value}`).join(", ");
    const gkResult = await GeminiService.runGatekeeperAgent(MOCK_RFP_CONTENT, constraintsText);

    setGatekeeperReasoning(gkResult.reasoning);

    if (gkResult.verdict === 'NO-GO') {
        addLog('Gatekeeper', 'CRITICAL STOP: No-Go signal triggered.', 'error');
        addLog('Gatekeeper', gkResult.reasoning.slice(0, 100) + "...", 'info');
        setSimState(prev => ({ ...prev, isActive: false, currentAgent: null, verdict: 'no-go' }));
        return;
    }

    addLog('Gatekeeper', `Verdict: ${gkResult.verdict}. Proceeding to drafting.`, 'success');
    setSimState(prev => ({ ...prev, verdict: 'go', progress: 50 }));
    await new Promise(r => setTimeout(r, 1000));

    // 3. Quant: Security Check
    setSimState(prev => ({ ...prev, currentAgent: 'Quant', progress: 65 }));
    addLog('Quant', 'Detected Security Questionnaire (Excel).', 'info');
    addLog('Quant', 'Generating Python script for cell A4: "Encryption Requirements"...', 'thinking');
    const pythonCode = await GeminiService.runQuantAgent("Must support AES-256 encryption at rest");
    addLog('Quant', `Generated Validator:\n${pythonCode}`, 'info');
    addLog('Quant', 'Compliance checks passed.', 'success');
    await new Promise(r => setTimeout(r, 1000));

    // 4. Architect: Drafting
    setSimState(prev => ({ ...prev, currentAgent: 'Architect', progress: 85 }));
    addLog('Architect', 'Synthesizing "Executive Summary" based on Winning DNA...', 'thinking');
    const draft = await GeminiService.runArchitectAgent(MOCK_RFP_CONTENT);
    setDraftContent(draft);
    addLog('Architect', 'Draft generation complete. Handing off to Auditor.', 'success');

    // 5. Auditor: Final Check
    setSimState(prev => ({ ...prev, currentAgent: 'Auditor', progress: 95 }));
    await new Promise(r => setTimeout(r, 800));
    addLog('Auditor', 'Verifying font compliance (Arial 11pt)... OK', 'success');
    addLog('Auditor', 'Checking page limit constraints... OK', 'success');

    // Finish
    setSimState(prev => ({ ...prev, isActive: false, currentAgent: null, progress: 100 }));
    addLog('System', 'Workflow Complete. Proposal ready for review.', 'success');
  };

  // --- Views ---

  const renderDashboard = () => (
    <div className="space-y-6 animate-fade-in">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-xl border border-brand-100 shadow-sm flex items-center space-x-4">
          <div className="p-3 bg-brand-50 rounded-lg text-brand-600">
            <Activity size={24} />
          </div>
          <div>
            <p className="text-sm text-slate-500 font-medium">Win Rate</p>
            <h3 className="text-2xl font-bold text-slate-900">42% <span className="text-sm font-normal text-emerald-600">(+12%)</span></h3>
          </div>
        </div>
        <div className="bg-white p-6 rounded-xl border border-brand-100 shadow-sm flex items-center space-x-4">
          <div className="p-3 bg-brand-50 rounded-lg text-brand-600">
             <BrainCircuit size={24} />
          </div>
          <div>
            <p className="text-sm text-slate-500 font-medium">Active Agents</p>
            <h3 className="text-2xl font-bold text-slate-900">5 <span className="text-sm font-normal text-slate-400">Idle</span></h3>
          </div>
        </div>
        <div className="bg-white p-6 rounded-xl border border-brand-100 shadow-sm flex items-center space-x-4">
          <div className="p-3 bg-brand-50 rounded-lg text-brand-600">
            <FileText size={24} />
          </div>
          <div>
            <p className="text-sm text-slate-500 font-medium">Proposals Generated</p>
            <h3 className="text-2xl font-bold text-slate-900">128</h3>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
          <h3 className="text-lg font-semibold text-slate-800 mb-4">Time Saved vs Manual (Hours)</h3>
          <div className="h-64">
             <ResponsiveContainer width="100%" height="100%">
                <BarChart data={[
                  { name: 'Oct', manual: 400, ai: 40 },
                  { name: 'Nov', manual: 300, ai: 35 },
                  { name: 'Dec', manual: 500, ai: 50 },
                  { name: 'Jan', manual: 200, ai: 15 },
                ]}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} />
                  <XAxis dataKey="name" />
                  <YAxis />
                  <Tooltip />
                  <Bar dataKey="manual" fill="#e2e8f0" radius={[4, 4, 0, 0]} name="Manual" />
                  <Bar dataKey="ai" fill="#0ea5e9" radius={[4, 4, 0, 0]} name="BidPilot AI" />
                </BarChart>
             </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-gradient-to-br from-brand-900 to-slate-900 p-6 rounded-xl text-white shadow-lg flex flex-col justify-between">
          <div>
            <div className="flex items-center space-x-2 mb-4">
              <Cpu className="text-brand-400" />
              <h3 className="font-semibold text-lg">Quick Actions</h3>
            </div>
            <p className="text-slate-300 text-sm mb-6">Start a new agentic workflow for the latest RFP.</p>
          </div>
          <button 
            onClick={runSimulation}
            className="w-full bg-brand-500 hover:bg-brand-400 text-white font-medium py-3 rounded-lg flex items-center justify-center transition-colors"
          >
            <Play size={18} className="mr-2" />
            Analyze New RFP
          </button>
        </div>
      </div>
    </div>
  );

  const renderAnalysis = () => (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 h-[calc(100vh-140px)]">
      {/* Live Terminal */}
      <div className="lg:col-span-2 flex flex-col glass-terminal rounded-xl border border-slate-700 shadow-2xl overflow-hidden">
        <div className="bg-slate-900/50 p-4 border-b border-slate-700 flex justify-between items-center">
          <div className="flex items-center space-x-2">
            <Terminal size={18} className="text-brand-400" />
            <span className="text-slate-200 font-mono text-sm">Agent_Swarm.sh</span>
          </div>
          <div className="flex space-x-2">
            <div className={`h-2 w-2 rounded-full ${simState.isActive ? 'bg-emerald-500 animate-pulse' : 'bg-slate-600'}`} />
            <div className="h-2 w-2 rounded-full bg-slate-600" />
            <div className="h-2 w-2 rounded-full bg-slate-600" />
          </div>
        </div>

        <div className="flex-1 p-6 overflow-y-auto terminal-scroll font-mono text-sm space-y-4">
          {logs.length === 0 && (
            <div className="text-slate-500 italic text-center mt-20">Waiting for mission start...</div>
          )}
          {logs.map((log) => (
            <div key={log.id} className="flex space-x-3 animate-fade-in-up">
              <span className="text-slate-500 shrink-0">[{log.timestamp}]</span>
              <div className="flex-1">
                <span className={`font-bold mr-2 ${
                  log.agent === 'Gatekeeper' ? 'text-rose-400' :
                  log.agent === 'Historian' ? 'text-amber-400' :
                  log.agent === 'Architect' ? 'text-brand-400' :
                  log.agent === 'Quant' ? 'text-purple-400' :
                  log.agent === 'Auditor' ? 'text-emerald-400' :
                  'text-slate-300'
                }`}>
                  {log.agent}:
                </span>
                <span className={log.type === 'error' ? 'text-rose-400' : log.type === 'thinking' ? 'text-brand-200 italic' : 'text-slate-300'}>
                  {log.message}
                </span>
              </div>
            </div>
          ))}
          <div ref={logsEndRef} />
        </div>
      </div>

      {/* Status Panel */}
      <div className="flex flex-col space-y-6">
         <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
            <h3 className="text-lg font-semibold mb-4 text-slate-800">Mission Status</h3>
            <div className="space-y-4">
              <div className="flex justify-between items-center">
                <span className="text-slate-600">Progress</span>
                <span className="font-mono text-brand-600">{simState.progress}%</span>
              </div>
              <div className="w-full bg-slate-100 rounded-full h-2">
                <div 
                  className="bg-brand-600 h-2 rounded-full transition-all duration-500" 
                  style={{ width: `${simState.progress}%` }}
                />
              </div>

