          </div>
          <div className="flex space-x-2">
             <button className="px-3 py-1.5 text-sm font-medium text-slate-600 hover:bg-white rounded-md border border-transparent hover:border-slate-200 transition-all">
                Export PDF
             </button>
             <button className="px-3 py-1.5 text-sm font-medium bg-brand-600 text-white rounded-md hover:bg-brand-700 transition-all">
                Finalize
             </button>
          </div>
       </div>
       <div className="flex-1 p-8 overflow-y-auto">
          <div className="max-w-3xl mx-auto space-y-8">
             {draftContent ? (
               <div className="prose prose-slate max-w-none">
                 <h1 className="text-3xl font-bold text-slate-900 mb-4">Executive Summary</h1>
                 <div className="whitespace-pre-wrap text-slate-700 leading-relaxed text-lg">
                    {draftContent}
                 </div>
               </div>
             ) : (
               <div className="text-center py-20">
                 <div className="bg-slate-50 rounded-full h-16 w-16 flex items-center justify-center mx-auto mb-4">
                    <PenTool className="text-slate-300" size={32} />
                 </div>
                 <h3 className="text-lg font-medium text-slate-900">No Draft Generated</h3>
                 <p className="text-slate-500 max-w-sm mx-auto mt-2">
