export default function BidPilotApp() {
  const [view, setView] = useState<'dashboard' | 'analysis' | 'knowledge' | 'draft'>('dashboard');
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [simState, setSimState] = useState<SimulationState>({
    isActive: false,
    currentAgent: null,
    progress: 0,
    verdict: 'pending'
  });
  const [draftContent, setDraftContent] = useState("");
  const [gatekeeperReasoning, setGatekeeperReasoning] = useState("");
  const logsEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (view === 'analysis') {
      logsEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }, [logs, view]);

  const addLog = (agent: LogEntry['agent'], message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [...prev, {
      id: Date.now(),
      agent,
      message,
      timestamp: new Date().toLocaleTimeString().split(' ')[0],
      type
    }]);
  };

  const runSimulation = async () => {
    if (simState.isActive) return;

    setView('analysis');
    setSimState({ isActive: true, currentAgent: 'Historian', progress: 0, verdict: 'pending' });
    setLogs([]);
    setDraftContent("");
    setGatekeeperReasoning("");

    addLog('System', 'Initializing Agent Swarm...', 'info');
    await new Promise(r => setTimeout(r, 800));

    addLog('Historian', 'Scanning Knowledge Base...', 'thinking');
    setSimState(prev => ({ ...prev, currentAgent: 'Historian', progress: 10 }));

    const histMsg = await GeminiService.runHistorianAgent(MOCK_KNOWLEDGE_BASE[0].name);
    addLog('Historian', histMsg, 'success');
    addLog('Historian', 'Cross-referencing 4 documents with RFP context.', 'info');
    await new Promise(r => setTimeout(r, 1000));

    addLog('Gatekeeper', 'Analyzing RFP against "Kill Switch" constraints...', 'thinking');
    setSimState(prev => ({ ...prev, currentAgent: 'Gatekeeper', progress: 30 }));

    const constraintsText = INITIAL_CONSTRAINTS.map(c => `${c.label}: ${c.value}`).join(", ");
    const gkResult = await GeminiService.runGatekeeperAgent(MOCK_RFP_CONTENT, constraintsText);

    setGatekeeperReasoning(gkResult.reasoning);

    if (gkResult.verdict === 'NO-GO') {
        addLog('Gatekeeper', 'CRITICAL STOP: No-Go signal triggered.', 'error');
        addLog('Gatekeeper', gkResult.reasoning.slice(0, 100) + "...", 'info');
        setSimState(prev => ({ ...prev, isActive: false, currentAgent: null, verdict: 'no-go' }));
