// --- Reusable Shadcn-like Components ---

interface ButtonProps {
  children?: React.ReactNode;
  variant?: "primary" | "secondary" | "ghost" | "outline" | "destructive";
  size?: "default" | "sm" | "icon";
  className?: string;
  onClick?: () => void;
  disabled?: boolean;
}

const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = "primary", 
  size = "default", 
  className = "", 
  onClick, 
  disabled 
}) => {
  const baseStyles = "inline-flex items-center justify-center rounded-md text-sm font-medium ring-offset-white transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-zinc-950 focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50";

  const variants = {
    primary: "bg-zinc-900 text-zinc-50 hover:bg-zinc-900/90 shadow-sm",
    secondary: "bg-zinc-100 text-zinc-900 hover:bg-zinc-100/80",
    ghost: "hover:bg-zinc-100 hover:text-zinc-900",
    outline: "border border-zinc-200 bg-white hover:bg-zinc-100 hover:text-zinc-900",
    destructive: "bg-red-500 text-zinc-50 hover:bg-red-500/90",
  };

  const sizes = {
    default: "h-9 px-4 py-2",
    sm: "h-8 rounded-md px-3 text-xs",
    icon: "h-9 w-9",
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${className}`}
      onClick={onClick}
      disabled={disabled}
    >
      {children}
    </button>
  );
};

interface CardProps {
  children?: React.ReactNode;
  className?: string;
}

const Card: React.FC<CardProps> = ({ children, className = "" }) => (
  <div className={`rounded-xl border border-zinc-200 bg-white text-zinc-950 shadow-sm ${className}`}>
    {children}
  </div>
);

const Badge = ({ children, variant = "default" }: { children?: React.ReactNode, variant?: string }) => {
  const styles: Record<string, string> = {
    default: "border-transparent bg-zinc-900 text-zinc-50 hover:bg-zinc-900/80",
    secondary: "border-transparent bg-zinc-100 text-zinc-900 hover:bg-zinc-100/80",
    outline: "text-zinc-950 border-zinc-200",
    destructive: "border-transparent bg-red-500 text-zinc-50 hover:bg-red-500/80",
    success: "border-transparent bg-emerald-500/15 text-emerald-700 hover:bg-emerald-500/25",
    warning: "border-transparent bg-amber-500/15 text-amber-700 hover:bg-amber-500/25",
    error: "border-transparent bg-rose-500/15 text-rose-700 hover:bg-rose-500/25",
    thinking: "border-transparent bg-violet-500/15 text-violet-700 animate-pulse",
  };

  return (
    <div className={`inline-flex items-center rounded-md border px-2.5 py-0.5 text-xs font-semibold transition-colors focus:outline-none focus:ring-2 focus:ring-zinc-950 focus:ring-offset-2 ${styles[variant] || styles.default}`}>
      {children}
    </div>
  );
};

// --- Main App ---

export default function BidPilotApp() {
  const [view, setView] = useState<'dashboard' | 'analysis' | 'knowledge' | 'draft'>('dashboard');
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [simState, setSimState] = useState<SimulationState>({
    isActive: false,
    currentAgent: null,
    progress: 0,
    verdict: 'pending'
  });
  const [draftContent, setDraftContent] = useState("");
  const [gatekeeperReasoning, setGatekeeperReasoning] = useState("");
  const logsEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (view === 'analysis') {
      logsEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }, [logs, view]);

  const addLog = (agent: LogEntry['agent'], message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [...prev, {
      id: Date.now(),
      agent,
      message,
      timestamp: new Date().toLocaleTimeString().split(' ')[0],
      type
    }]);
  };

  const runSimulation = async () => {
    if (simState.isActive) return;

    setView('analysis');
    setSimState({ isActive: true, currentAgent: 'Historian', progress: 0, verdict: 'pending' });
    setLogs([]);
    setDraftContent("");
    setGatekeeperReasoning("");

    addLog('System', 'Initializing Agent Swarm...', 'info');
    await new Promise(r => setTimeout(r, 800));

    addLog('Historian', 'Scanning Knowledge Base...', 'thinking');
    setSimState(prev => ({ ...prev, currentAgent: 'Historian', progress: 10 }));

    const histMsg = await GeminiService.runHistorianAgent(MOCK_KNOWLEDGE_BASE[0].name);
    addLog('Historian', histMsg, 'success');
    addLog('Historian', 'Cross-referencing 4 documents with RFP context.', 'info');
    await new Promise(r => setTimeout(r, 1000));

    addLog('Gatekeeper', 'Analyzing RFP against "Kill Switch" constraints...', 'thinking');
    setSimState(prev => ({ ...prev, currentAgent: 'Gatekeeper', progress: 30 }));

    const constraintsText = INITIAL_CONSTRAINTS.map(c => `${c.label}: ${c.value}`).join(", ");
    const gkResult = await GeminiService.runGatekeeperAgent(MOCK_RFP_CONTENT, constraintsText);

    setGatekeeperReasoning(gkResult.reasoning);

    if (gkResult.verdict === 'NO-GO') {
        addLog('Gatekeeper', 'CRITICAL STOP: No-Go signal triggered.', 'error');
        addLog('Gatekeeper', gkResult.reasoning.slice(0, 100) + "...", 'info');
        setSimState(prev => ({ ...prev, isActive: false, currentAgent: null, verdict: 'no-go' }));
        return;
    }

    addLog('Gatekeeper', `Verdict: ${gkResult.verdict}. Proceeding to drafting.`, 'success');
    setSimState(prev => ({ ...prev, verdict: 'go', progress: 50 }));
    await new Promise(r => setTimeout(r, 1000));

    setSimState(prev => ({ ...prev, currentAgent: 'Quant', progress: 65 }));
    addLog('Quant', 'Detected Security Questionnaire (Excel).', 'info');
    addLog('Quant', 'Generating Python script for cell A4: "Encryption Requirements"...', 'thinking');
    const pythonCode = await GeminiService.runQuantAgent("Must support AES-256 encryption at rest");
    addLog('Quant', `Generated Validator:\n${pythonCode}`, 'info');
    addLog('Quant', 'Compliance checks passed.', 'success');
    await new Promise(r => setTimeout(r, 1000));

    setSimState(prev => ({ ...prev, currentAgent: 'Architect', progress: 85 }));
    addLog('Architect', 'Synthesizing "Executive Summary" based on Winning DNA...', 'thinking');
    const draft = await GeminiService.runArchitectAgent(MOCK_RFP_CONTENT);
    setDraftContent(draft);
    addLog('Architect', 'Draft generation complete. Handing off to Auditor.', 'success');

    setSimState(prev => ({ ...prev, currentAgent: 'Auditor', progress: 95 }));
    await new Promise(r => setTimeout(r, 800));
    addLog('Auditor', 'Verifying font compliance (Arial 11pt)... OK', 'success');
    addLog('Auditor', 'Checking page limit constraints... OK', 'success');

    setSimState(prev => ({ ...prev, isActive: false, currentAgent: null, progress: 100 }));
    addLog('System', 'Workflow Complete. Proposal ready for review.', 'success');
  };

  const renderDashboard = () => (
    <div className="space-y-6 animate-in">
      <div className="flex items-center justify-between">
        <h2 className="text-3xl font-bold tracking-tight">Dashboard</h2>
        <div className="flex items-center space-x-2">
           <Button variant="outline" size="sm" className="hidden md:flex">
              <Clock className="mr-2 h-4 w-4" />
              History
           </Button>
           <Button onClick={runSimulation} className="bg-zinc-900 text-white hover:bg-zinc-800">
              <Play className="mr-2 h-4 w-4" />
