                      <Tooltip 
                        contentStyle={{ backgroundColor: '#fff', borderRadius: '8px', border: '1px solid #e4e4e7', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                        itemStyle={{ color: '#09090b', fontSize: '12px' }}
                      />
                      <Bar dataKey="manual" fill="#e4e4e7" radius={[4, 4, 0, 0]} name="Manual Hours" />
                      <Bar dataKey="ai" fill="#18181b" radius={[4, 4, 0, 0]} name="AI Hours" />
                    </BarChart>
                </ResponsiveContainer>
             </div>
          </div>
        </Card>
        <Card className="col-span-3 p-6 flex flex-col justify-between">
            <div>
              <h3 className="text-lg font-medium mb-1">Recent Activity</h3>
              <p className="text-sm text-zinc-500 mb-6">Latest agent actions</p>
              <div className="space-y-4">
                 {[1,2,3].map(i => (
                   <div key={i} className="flex items-start space-x-3 pb-3 border-b border-zinc-50 last:border-0">
                      <div className="h-8 w-8 rounded-full bg-zinc-100 flex items-center justify-center text-zinc-500">
                        <BrainCircuit size={14} />
                      </div>
                      <div>
                        <p className="text-sm font-medium text-zinc-900">Analyzed Project {i}</p>
                        <p className="text-xs text-zinc-500">2 hours ago</p>
                      </div>
                   </div>
                 ))}
              </div>
            </div>
            <Button variant="outline" className="w-full mt-4">View All Logs</Button>
        </Card>
      </div>
    </div>
  );

  const renderAnalysis = () => (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 h-[calc(100vh-100px)] animate-in">
      <div className="lg:col-span-2 flex flex-col rounded-xl border border-zinc-800 bg-zinc-950 overflow-hidden shadow-2xl">
        <div className="flex items-center justify-between border-b border-zinc-800 bg-zinc-900/50 px-4 py-3">
          <div className="flex items-center space-x-2">
            <div className="flex space-x-1.5">
              <div className="h-3 w-3 rounded-full bg-red-500/80" />
              <div className="h-3 w-3 rounded-full bg-amber-500/80" />
              <div className="h-3 w-3 rounded-full bg-emerald-500/80" />
            </div>
            <span className="ml-2 font-mono text-xs text-zinc-400">bidpilot-cli — node agent.js</span>
          </div>
          <div className="flex items-center space-x-2">
            {simState.isActive && <Activity className="h-3 w-3 text-emerald-500 animate-pulse" />}
            <span className="text-xs text-zinc-500">{simState.isActive ? 'RUNNING' : 'IDLE'}</span>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-4 font-mono text-xs md:text-sm text-zinc-300 terminal-scroll">
