interface ButtonProps {
  children?: React.ReactNode;
  variant?: "primary" | "secondary" | "ghost" | "outline" | "destructive";
  size?: "default" | "sm" | "icon";
  className?: string;
  onClick?: () => void;
  disabled?: boolean;
}

const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = "primary", 
  size = "default", 
  className = "", 
  onClick, 
  disabled 
}) => {
  const baseStyles = "inline-flex items-center justify-center rounded-md text-sm font-medium ring-offset-white transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-zinc-950 focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50";

  const variants = {
    primary: "bg-zinc-900 text-zinc-50 hover:bg-zinc-900/90 shadow-sm",
    secondary: "bg-zinc-100 text-zinc-900 hover:bg-zinc-100/80",
    ghost: "hover:bg-zinc-100 hover:text-zinc-900",
    outline: "border border-zinc-200 bg-white hover:bg-zinc-100 hover:text-zinc-900",
    destructive: "bg-red-500 text-zinc-50 hover:bg-red-500/90",
  };

  const sizes = {
    default: "h-9 px-4 py-2",
    sm: "h-8 rounded-md px-3 text-xs",
    icon: "h-9 w-9",
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${className}`}
      onClick={onClick}
      disabled={disabled}
    >
      {children}
    </button>
  );
};

interface CardProps {
  children?: React.ReactNode;
  className?: string;
}

const Card: React.FC<CardProps> = ({ children, className = "" }) => (
  <div className={`rounded-xl border border-zinc-200 bg-white text-zinc-950 shadow-sm ${className}`}>
    {children}
  </div>
);

const Badge = ({ children, variant = "default" }: { children?: React.ReactNode, variant?: string }) => {
  const styles: Record<string, string> = {
    default: "border-transparent bg-zinc-900 text-zinc-50 hover:bg-zinc-900/80",
    secondary: "border-transparent bg-zinc-100 text-zinc-900 hover:bg-zinc-100/80",
    outline: "text-zinc-950 border-zinc-200",
    destructive: "border-transparent bg-red-500 text-zinc-50 hover:bg-red-500/80",
    success: "border-transparent bg-emerald-500/15 text-emerald-700 hover:bg-emerald-500/25",
    warning: "border-transparent bg-amber-500/15 text-amber-700 hover:bg-amber-500/25",
    error: "border-transparent bg-rose-500/15 text-rose-700 hover:bg-rose-500/25",
    thinking: "border-transparent bg-violet-500/15 text-violet-700 animate-pulse",
  };

  return (
    <div className={`inline-flex items-center rounded-md border px-2.5 py-0.5 text-xs font-semibold transition-colors focus:outline-none focus:ring-2 focus:ring-zinc-950 focus:ring-offset-2 ${styles[variant] || styles.default}`}>
      {children}
    </div>
  );
};

// --- Main App ---

export default function BidPilotApp() {
  const [view, setView] = useState<'dashboard' | 'setup' | 'analysis' | 'knowledge' | 'draft'>('dashboard');

  // App State
  const [documents, setDocuments] = useState<Document[]>(MOCK_KNOWLEDGE_BASE);
  const [constraints, setConstraints] = useState<Constraint[]>(INITIAL_CONSTRAINTS);
  const [rfpInput, setRfpInput] = useState(MOCK_RFP_CONTENT);

  // Simulation State
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [simState, setSimState] = useState<SimulationState>({
    isActive: false,
    currentAgent: null,
    progress: 0,
    verdict: 'pending'
  });
  const [draftContent, setDraftContent] = useState("");
  const [gatekeeperReasoning, setGatekeeperReasoning] = useState("");
  const logsEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (view === 'analysis') {
      logsEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }, [logs, view]);

  const addLog = (agent: LogEntry['agent'], message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [...prev, {
      id: Date.now(),
      agent,
      message,
      timestamp: new Date().toLocaleTimeString().split(' ')[0],
      type
    }]);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const newDoc: Document = {
      id: Date.now(),
      name: file.name,
      size: `${(file.size / 1024 / 1024).toFixed(1)}MB`,
      date: new Date().toLocaleDateString('en-US', { month: 'short', year: 'numeric' }),
      tags: ["New"],
      type: file.name.endsWith('xlsx') ? 'xlsx' : 'pdf',
      status: 'pending'
    };

    setDocuments(prev => [newDoc, ...prev]);

    // Simulate indexing
    setTimeout(() => {
      setDocuments(prev => prev.map(d => d.id === newDoc.id ? { ...d, status: 'indexed' } : d));
    }, 2000);
  };

  const runSimulation = async () => {
    if (simState.isActive) return;

    setView('analysis');
    setSimState({ isActive: true, currentAgent: 'Historian', progress: 0, verdict: 'pending' });
    setLogs([]);
    setDraftContent("");
    setGatekeeperReasoning("");

    // 1. Historian: Ingest
    addLog('System', 'Initializing Agent Swarm...', 'info');
    await new Promise(r => setTimeout(r, 800));

    addLog('Historian', `Scanning Knowledge Base (${documents.length} documents)...`, 'thinking');
    setSimState(prev => ({ ...prev, currentAgent: 'Historian', progress: 10 }));

    // Simulate reading the last added doc
    const latestDoc = documents[0];
    const histMsg = await GeminiService.runHistorianAgent(latestDoc.name);
    addLog('Historian', histMsg, 'success');
    addLog('Historian', 'Context vector database updated.', 'info');
    await new Promise(r => setTimeout(r, 1000));

    // 2. Gatekeeper: Analysis
    addLog('Gatekeeper', 'Analyzing RFP against Deal Breaker constraints...', 'thinking');
    setSimState(prev => ({ ...prev, currentAgent: 'Gatekeeper', progress: 30 }));

    const gkResult = await GeminiService.runGatekeeperAgent(rfpInput, constraints);

    setGatekeeperReasoning(gkResult.reasoning);

    if (gkResult.verdict === 'NO-GO') {
        addLog('Gatekeeper', 'CRITICAL STOP: No-Go signal triggered.', 'error');
        addLog('Gatekeeper', gkResult.reasoning, 'info');
        setSimState(prev => ({ ...prev, isActive: false, currentAgent: null, verdict: 'no-go' }));
        return;
    }

    addLog('Gatekeeper', `Verdict: ${gkResult.verdict}. Proceeding to drafting.`, 'success');
    setSimState(prev => ({ ...prev, verdict: 'go', progress: 50 }));
    await new Promise(r => setTimeout(r, 1000));

    // 3. Quant: Security Check
    setSimState(prev => ({ ...prev, currentAgent: 'Quant', progress: 65 }));
    addLog('Quant', 'Detected Security Requirements section.', 'info');
    addLog('Quant', 'Generating Python script validation logic...', 'thinking');
    const pythonCode = await GeminiService.runQuantAgent("Encryption Standards");
    addLog('Quant', `Generated Validator:\n${pythonCode}`, 'info');
    addLog('Quant', 'Compliance checks passed.', 'success');
    await new Promise(r => setTimeout(r, 1000));

    // 4. Architect: Drafting
    setSimState(prev => ({ ...prev, currentAgent: 'Architect', progress: 85 }));
    addLog('Architect', 'Synthesizing "Executive Summary" based on Winning DNA...', 'thinking');
    const draft = await GeminiService.runArchitectAgent(rfpInput);
    setDraftContent(draft);
    addLog('Architect', 'Draft generation complete. Handing off to Auditor.', 'success');

    // 5. Auditor: Final Check
    setSimState(prev => ({ ...prev, currentAgent: 'Auditor', progress: 95 }));
    await new Promise(r => setTimeout(r, 800));
    addLog('Auditor', 'Verifying font compliance (Arial 11pt)... OK', 'success');
    addLog('Auditor', 'Checking page limit constraints... OK', 'success');

    // Finish
    setSimState(prev => ({ ...prev, isActive: false, currentAgent: null, progress: 100 }));
    addLog('System', 'Workflow Complete. Proposal ready for review.', 'success');
  };

  // --- Views ---

  const renderDashboard = () => (
    <div className="space-y-6 animate-in">
      <div className="flex items-center justify-between">
        <h2 className="text-3xl font-bold tracking-tight">Dashboard</h2>
        <div className="flex items-center space-x-2">
           <Button variant="outline" size="sm" className="hidden md:flex">
              <Clock className="mr-2 h-4 w-4" />
              History
           </Button>
           <Button onClick={() => setView('setup')} className="bg-zinc-900 text-white hover:bg-zinc-800">
              <Play className="mr-2 h-4 w-4" />
              New Analysis
           </Button>
        </div>
      </div>

      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
         <Card className="p-6">
            <div className="flex flex-row items-center justify-between space-y-0 pb-2">
              <div className="text-sm font-medium text-zinc-500">Total Win Rate</div>
              <Activity className="h-4 w-4 text-zinc-500" />
            </div>
            <div className="text-2xl font-bold">42.5%</div>
            <p className="text-xs text-zinc-500">+12% from last month</p>
         </Card>
         <Card className="p-6">
            <div className="flex flex-row items-center justify-between space-y-0 pb-2">
              <div className="text-sm font-medium text-zinc-500">Active Proposals</div>
              <FileText className="h-4 w-4 text-zinc-500" />
            </div>
            <div className="text-2xl font-bold">12</div>
            <p className="text-xs text-zinc-500">3 due this week</p>
         </Card>
         <Card className="p-6">
            <div className="flex flex-row items-center justify-between space-y-0 pb-2">
              <div className="text-sm font-medium text-zinc-500">Time Saved</div>
              <Clock className="h-4 w-4 text-zinc-500" />
            </div>
            <div className="text-2xl font-bold">124h</div>
            <p className="text-xs text-zinc-500">This quarter</p>
         </Card>
         <Card className="p-6">
            <div className="flex flex-row items-center justify-between space-y-0 pb-2">
              <div className="text-sm font-medium text-zinc-500">Knowledge Base</div>
              <Database className="h-4 w-4 text-zinc-500" />
            </div>
            <div className="text-2xl font-bold">{documents.length}</div>
            <p className="text-xs text-zinc-500">Indexed documents</p>
         </Card>
      </div>

      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-7">
        <Card className="col-span-4">
          <div className="p-6">
             <h3 className="text-lg font-medium leading-6 text-zinc-900">Efficiency Metrics</h3>
             <p className="text-sm text-zinc-500">Manual vs. Autonomous Proposal Generation</p>
             <div className="mt-6 h-[300px] w-full">
                <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={[
                      { name: 'Oct', manual: 400, ai: 40 },
                      { name: 'Nov', manual: 300, ai: 35 },
                      { name: 'Dec', manual: 500, ai: 50 },
                      { name: 'Jan', manual: 200, ai: 15 },
                    ]}>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e4e4e7" />
                      <XAxis dataKey="name" stroke="#71717a" fontSize={12} tickLine={false} axisLine={false} />
                      <YAxis stroke="#71717a" fontSize={12} tickLine={false} axisLine={false} tickFormatter={(value) => `${value}h`} />
                      <Tooltip 
                        contentStyle={{ backgroundColor: '#fff', borderRadius: '8px', border: '1px solid #e4e4e7', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                        itemStyle={{ color: '#09090b', fontSize: '12px' }}
                      />
                      <Bar dataKey="manual" fill="#e4e4e7" radius={[4, 4, 0, 0]} name="Manual Hours" />
                      <Bar dataKey="ai" fill="#18181b" radius={[4, 4, 0, 0]} name="AI Hours" />
                    </BarChart>
                </ResponsiveContainer>
             </div>
          </div>
        </Card>
        <Card className="col-span-3 p-6 flex flex-col justify-between">
            <div>
              <h3 className="text-lg font-medium mb-1">Recent Activity</h3>
              <p className="text-sm text-zinc-500 mb-6">Latest agent actions</p>
              <div className="space-y-4">
                 {[1,2,3].map(i => (
                   <div key={i} className="flex items-start space-x-3 pb-3 border-b border-zinc-50 last:border-0">
                      <div className="h-8 w-8 rounded-full bg-zinc-100 flex items-center justify-center text-zinc-500">
                        <BrainCircuit size={14} />
                      </div>
                      <div>
                        <p className="text-sm font-medium text-zinc-900">Analyzed Project {i}</p>
                        <p className="text-xs text-zinc-500">2 hours ago</p>
                      </div>
                   </div>
                 ))}
              </div>
            </div>
            <Button variant="outline" className="w-full mt-4">View All Logs</Button>
        </Card>
      </div>
    </div>
  );

  const renderSetup = () => (
    <div className="space-y-6 animate-in max-w-4xl mx-auto">
      <div className="flex items-center space-x-2 mb-6">
        <Button variant="ghost" size="sm" onClick={() => setView('dashboard')}>
