                setConstraints([...constraints, { id: newId, label: 'New Constraint', value: '', type: 'text' }]);
             }}>
               <Plus className="h-4 w-4 mr-2" /> Add
             </Button>
           </div>
           <div className="space-y-3">
             {constraints.map((c, idx) => (
               <div key={c.id} className="flex items-center space-x-3">
                  <div className="w-1/3">
                    <input 
                      type="text" 
                      value={c.label}
                      onChange={(e) => {
                        const newC = [...constraints];
                        newC[idx].label = e.target.value;
                        setConstraints(newC);
                      }}
                      className="w-full px-3 py-2 rounded-md border border-zinc-200 text-sm focus:outline-none focus:border-zinc-400"
                    />
                  </div>
                  <div className="flex-1">
                    <input 
                      type="text" 
                      value={c.value}
                      onChange={(e) => {
                        const newC = [...constraints];
                        newC[idx].value = e.target.value;
                        setConstraints(newC);
                      }}
                      className="w-full px-3 py-2 rounded-md border border-zinc-200 text-sm focus:outline-none focus:border-zinc-400"
                    />
                  </div>
                  <Button variant="ghost" size="icon" onClick={() => {
                     setConstraints(constraints.filter(item => item.id !== c.id));
                  }}>
                    <Trash2 className="h-4 w-4 text-zinc-400 hover:text-red-500" />
                  </Button>
               </div>
             ))}
           </div>
        </Card>
      </div>

      <div className="flex justify-end pt-4">
        <Button size="default" className="w-full md:w-auto px-8" onClick={runSimulation}>
           <Play className="h-4 w-4 mr-2" /> Start Autonomous Agents
        </Button>
      </div>
    </div>
  );

  const renderAnalysis = () => (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 h-[calc(100vh-100px)] animate-in">
      <div className="lg:col-span-2 flex flex-col rounded-xl border border-zinc-800 bg-zinc-950 overflow-hidden shadow-2xl relative">

        {/* Grid Scan Background Effect */}
        <div 
          className={`absolute inset-0 z-0 ${simState.isActive ? 'opacity-30' : 'opacity-5'} transition-opacity duration-1000 pointer-events-none`}
          style={{ perspective: '1000px', overflow: 'hidden' }}
        >
          <div 
            className={`absolute inset-[-100%] origin-bottom ${simState.isActive ? 'animate-grid-scroll' : ''}`}
            style={{
