              <h3 className="text-lg font-medium mb-1">Recent Activity</h3>
              <p className="text-sm text-zinc-500 dark:text-zinc-400 mb-6">Latest agent actions</p>
              <div className="space-y-4">
                 {[1,2,3].map(i => (
