              <Activity className="h-4 w-4 text-zinc-500 dark:text-zinc-400" />
            </div>
            <div className="text-2xl font-bold">42.5%</div>
            <p className="text-xs text-zinc-500 dark:text-zinc-400">+12% from last month</p>
         </Card>
         <Card className="p-6">
